# ── Security: HTTP headers ────────────────────────────────────────────────────
@app.after_request
def _set_security_headers(response):
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'SAMEORIGIN'
    response.headers['Referrer-Policy'] = 'strict-origin-when-cross-origin'
    # Allow microphone on /gemini page (needed for Barge In), block everywhere else
    if request.path.startswith('/gemini'):
        response.headers['Permissions-Policy'] = 'camera=(), microphone=(self), geolocation=()'
    else:
        response.headers['Permissions-Policy'] = 'camera=(), microphone=(), geolocation=()'
    if request.is_secure:
        response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    # CSP: allow inline scripts/styles (needed for dashboard), plus CDNs used
    response.headers['Content-Security-Policy'] = (
        "default-src 'self'; "
        "script-src 'self' 'unsafe-inline' https://cdn.jsdelivr.net https://www.google.com https://www.gstatic.com; "
        "style-src 'self' 'unsafe-inline' https://cdnjs.cloudflare.com https://fonts.googleapis.com; "
        "font-src 'self' https://cdnjs.cloudflare.com https://fonts.gstatic.com; "
        "img-src 'self' data: https://*.supabase.co https://www.gstatic.com; "
        "connect-src 'self' https://*.supabase.co https://cdn.jsdelivr.net https://*.azurewebsites.net wss://*.azurewebsites.net; "
        "frame-src https://www.google.com; "
        "object-src 'none'; "
        "base-uri 'self'"
    )
    return response

# ── Security: Rate limiting ───────────────────────────────────────────────────
import collections as _collections
_rate_buckets = _collections.defaultdict(list)   # key → [timestamps]

def _rate_limit(key, max_requests, window_seconds):
    """Return True if rate limit exceeded. Lightweight in-memory sliding window."""
    import time as _rl_time
    now = _rl_time.time()
    cutoff = now - window_seconds
    bucket = _rate_buckets[key]
    # Prune expired entries
    _rate_buckets[key] = [t for t in bucket if t > cutoff]
    if len(_rate_buckets[key]) >= max_requests:
        return True
    _rate_buckets[key].append(now)
    return False

def _get_git_version():
    """Return cached git version string (hash + NZ date). Refreshes every 5 min."""
    gv = getattr(app, '_cached_git_version', None)
    _age = _time.time() - getattr(app, '_cached_git_version_at', 0)
    if gv and _age <= 300:
        return gv
    gv = "unknown"
    if GITHUB_PAT and GITHUB_REPO:
        try:
            _r = requests.get(
                f"https://api.github.com/repos/{GITHUB_REPO}/commits/main",
                headers={"Authorization": f"token {GITHUB_PAT}", "Accept": "application/vnd.github.v3+json"},
                timeout=5,
            )
            if _r.ok:
                _c = _r.json()
                from datetime import datetime as _dt
                try:
                    _utc = _dt.fromisoformat(_c["commit"]["committer"]["date"].replace("Z", "+00:00"))
                    from zoneinfo import ZoneInfo as _ZI
                    _nz = _utc.astimezone(_ZI("Pacific/Auckland"))
                    _gdate = _nz.strftime("%Y-%m-%d %H:%M")
                except Exception:
                    _gdate = _c["commit"]["committer"]["date"][:16].replace("T", " ")
                gv = f"{_c['sha'][:7]} {_gdate}"
        except Exception:
            pass
    if gv == "unknown":
        try:
            _env = {**os.environ, "TZ": "Pacific/Auckland"}
            _gh = subprocess.run(["git", "log", "-1", "--format=%h %cd", "--date=format:%d %b %Y %H:%M"],
                                 capture_output=True, text=True, cwd=BASE_DIR, env=_env)
            gv = _gh.stdout.strip() if _gh.returncode == 0 else "unknown"
        except Exception:
            pass
    app._cached_git_version = gv
    app._cached_git_version_at = _time.time()
    return gv

def _get_client_ip():
    return request.headers.get('X-Forwarded-For', request.remote_addr or '').split(',')[0].strip()

