# ── TOTP 2FA helpers ──────────────────────────────────────────────────────────

def _totp_fernet():
    """Return a Fernet instance for encrypting/decrypting TOTP secrets."""
    key = os.getenv("TOTP_ENCRYPTION_KEY")
    if not key:
        # Derive deterministically from existing secrets
        raw = _hashlib.sha256(
            (PAGES_PASSWORD + (SUPABASE_SERVICE_KEY or "")).encode()
        ).digest()
        key = _b64.urlsafe_b64encode(raw).decode()
    return Fernet(key.encode() if isinstance(key, str) else key)

def _totp_encrypt(plaintext):
    """Fernet-encrypt a string, return base64-encoded ciphertext."""
    return _totp_fernet().encrypt(plaintext.encode()).decode()

def _totp_decrypt(ciphertext):
    """Fernet-decrypt a ciphertext string, return plaintext."""
    return _totp_fernet().decrypt(ciphertext.encode()).decode()

_2FA_REMEMBER_DAYS = 30

def _make_2fa_remember_token(email):
    """Create an HMAC-signed token: email|expiry|signature."""
    expiry = int(_time.time()) + (_2FA_REMEMBER_DAYS * 86400)
    msg = f"{email}|{expiry}"
    sig = _hmac.new(app.secret_key.encode() if isinstance(app.secret_key, str) else app.secret_key,
                    msg.encode(), _hashlib.sha256).hexdigest()[:32]
    return f"{msg}|{sig}"

def _verify_2fa_remember_token(token, email):
    """Check if a remember-device token is valid and not expired."""
    try:
        parts = token.split('|')
        if len(parts) != 3:
            return False
        tok_email, tok_expiry, tok_sig = parts
        if tok_email != email:
            return False
        if int(tok_expiry) < int(_time.time()):
            return False
        expected_msg = f"{tok_email}|{tok_expiry}"
        expected_sig = _hmac.new(app.secret_key.encode() if isinstance(app.secret_key, str) else app.secret_key,
                                 expected_msg.encode(), _hashlib.sha256).hexdigest()[:32]
        return _hmac.compare_digest(tok_sig, expected_sig)
    except Exception:
        return False

def _generate_backup_codes(count=8):
    """Generate a list of single-use backup codes in XXXXX-XXXXX format."""
    codes = []
    for _ in range(count):
        part1 = ''.join([str(_secrets.randbelow(10)) for _ in range(5)])
        part2 = ''.join([str(_secrets.randbelow(10)) for _ in range(5)])
        codes.append({"code": f"{part1}-{part2}", "used": False})
    return codes

def _get_user_totp_row(email):
    """Fetch TOTP columns for a user from allowed_users."""
    try:
        r = requests.get(f"{SUPABASE_URL}/rest/v1/allowed_users",
                         params={"email": f"eq.{email}", "active": "eq.true",
                                 "select": "id,totp_secret,totp_enabled,totp_backup_codes,totp_enabled_at"},
                         headers={"apikey": SUPABASE_SERVICE_KEY,
                                  "Authorization": f"Bearer {SUPABASE_SERVICE_KEY}"},
                         timeout=10)
        if r.ok and r.json():
            return r.json()[0]
    except Exception:
        pass
    return None

def _verify_totp_code(secret, code):
    """Verify a TOTP code with ±1 window (90 seconds tolerance)."""
    try:
        return pyotp.TOTP(secret).verify(code.strip(), valid_window=1)
    except Exception:
        return False

def _verify_backup_code(email, submitted_code):
    """Check a backup code, mark it used if valid. Returns True if consumed."""
    row = _get_user_totp_row(email)
    if not row or not row.get('totp_backup_codes'):
        return False
    try:
        codes = json.loads(_totp_decrypt(row['totp_backup_codes']))
    except Exception:
        return False
    submitted = submitted_code.strip().replace(' ', '')
    found = False
    for c in codes:
        if c['code'] == submitted and not c['used']:
            c['used'] = True
            found = True
            break
    if not found:
        return False
    # Save updated codes back
    try:
        encrypted = _totp_encrypt(json.dumps(codes))
        requests.patch(f"{SUPABASE_URL}/rest/v1/allowed_users",
                       params={"id": f"eq.{row['id']}"},
                       json={"totp_backup_codes": encrypted},
                       headers={"apikey": SUPABASE_SERVICE_KEY,
                                "Authorization": f"Bearer {SUPABASE_SERVICE_KEY}",
                                "Prefer": "return=minimal"},
                       timeout=10)
    except Exception:
        pass
    return True

# ── End TOTP helpers ──────────────────────────────────────────────────────────

_CUSTOM_DOMAIN = os.getenv("CUSTOM_DOMAIN", "psplachecker.co.nz")

@app.before_request
def _redirect_to_custom_domain():
    """Redirect old Azure default hostname to the custom domain."""
    host = request.host.split(":")[0]
    if _CUSTOM_DOMAIN and host.endswith(".azurewebsites.net"):
        return redirect(request.url.replace(host, _CUSTOM_DOMAIN, 1), code=301)

@app.before_request
def _require_dashboard_auth():
    if request.endpoint in _AUTH_SKIP or (request.endpoint or '').startswith('static'):
        return
    if session.get('2fa_pending'):
        return redirect(url_for('auth_2fa_page'))
    if not session.get('authenticated'):
        return redirect(url_for('login_page'))
    # ── CSRF check on all authenticated POST/DELETE/PATCH/PUT ──
    csrf_err = _check_csrf()
    if csrf_err:
        return csrf_err
    # ── Permission check ──
    _perm_group = _ROUTE_PERMISSIONS.get(request.endpoint)
    if _perm_group:
        _denied = _require_permission(_perm_group)
        if _denied:
            return _denied

