@app.route('/login')
def login_page():
    _local_addrs = ('127.0.0.1', '::1', '0.0.0.0', '::ffff:127.0.0.1')
    is_local = request.remote_addr in _local_addrs
    local_pw = (
        '<div class="divider">\u2014 or local password \u2014</div>'
        '<input type="password" id="pw-input" class="pw-input" placeholder="Dashboard password"'
        ' onkeydown="if(event.key===\'Enter\')checkPassword()">'
        '<button class="btn-unlock" onclick="checkPassword()">Unlock</button>'
    ) if is_local else ''
    err = request.args.get('e', '')
    _login_msgs = {
        'denied': ('Your Google account is not on the authorised list.', 'error'),
        'access_requested': (
            '<i class="fa-solid fa-paper-plane" style="margin-right:4px"></i> '
            'Your access request has been sent to the administrator. '
            'You\'ll receive an email when your access is approved.', 'warn'),
        'access_pending': (
            '<i class="fa-solid fa-clock" style="margin-right:4px"></i> '
            'Your access request is still pending review by the administrator. '
            'Please check back later.', 'warn'),
        'access_rejected': (
            '<i class="fa-solid fa-circle-xmark" style="margin-right:4px"></i> '
            'Unfortunately your access request was not approved at this time. '
            'If you believe this is an error, please contact the administrator.', 'reject'),
    }
    if err in _login_msgs:
        msg, msg_class = _login_msgs[err]
    elif err:
        msg, msg_class = 'Sign-in error — please try again.', 'error'
    else:
        msg, msg_class = '', ''
    html = (_DASH_LOGIN_HTML
            .replace('__SB_URL__', SUPABASE_URL or '')
            .replace('__SB_ANON__', SUPABASE_ANON_KEY or '')
            .replace('__LOCAL_PW__', local_pw)
            .replace('__MSG__', msg)
            .replace('__MSG_CLASS__', msg_class))
    return html

@app.route('/login/password', methods=['POST'])
def login_password():
    rl = _check_rate_limit('login', 5, 60)
    if rl: return rl
    _local_addrs = ('127.0.0.1', '::1', '0.0.0.0', '::ffff:127.0.0.1')
    remote = request.remote_addr
    # Behind a reverse proxy (Azure/gunicorn), check X-Forwarded-For
    if remote not in _local_addrs and request.headers.get('X-Forwarded-For'):
        remote = request.headers.get('X-Forwarded-For', '').split(',')[0].strip()
    if remote not in _local_addrs:
        return _jsonify_auth({'ok': False, 'error': 'localhost only'}), 403
    pw = (request.json or {}).get('password', '')
    if _hashlib.sha256(pw.encode()).hexdigest() == _hashlib.sha256(PAGES_PASSWORD.encode()).hexdigest():
        session['authenticated'] = True
        session['email'] = 'wade (local)'
        session['auth_method'] = 'password'
        return _jsonify_auth({'ok': True})
    return _jsonify_auth({'ok': False}), 401

@app.route('/auth/callback')
def auth_callback():
    return (_DASH_CALLBACK_HTML
            .replace('__SB_URL__', SUPABASE_URL or '')
            .replace('__SB_ANON__', SUPABASE_ANON_KEY or ''))

@app.route('/auth/verify', methods=['POST'])
def auth_verify():
    rl = _check_rate_limit('auth', 10, 60)
    if rl: return rl
    data = request.json or {}
    access_token = data.get('access_token', '')
    email = data.get('email', '').lower().strip()
    if not access_token or not email:
        return _jsonify_auth({'ok': False, 'error': 'missing_token'})
    # Validate the token by fetching the user from Supabase Auth
    try:
        r = requests.get(f"{SUPABASE_URL}/auth/v1/user",
                         headers={'Authorization': f'Bearer {access_token}',
                                  'apikey': SUPABASE_ANON_KEY},
                         timeout=10)
        if r.status_code != 200:
            return _jsonify_auth({'ok': False, 'error': 'invalid_token'})
        if r.json().get('email', '').lower().strip() != email:
            return _jsonify_auth({'ok': False, 'error': 'email_mismatch'})
    except Exception:
        return _jsonify_auth({'ok': False, 'error': 'auth_error'})
    # Check allowed_users table using service key (bypasses RLS)
    try:
        r2 = requests.get(f"{SUPABASE_URL}/rest/v1/allowed_users",
                          params={'email': f'eq.{email}', 'active': 'eq.true', 'select': 'id,is_admin,permissions'},
                          headers={'apikey': SUPABASE_SERVICE_KEY,
                                   'Authorization': f'Bearer {SUPABASE_SERVICE_KEY}'},
                          timeout=10)
        if r2.status_code == 200 and r2.json():
            _user_row = r2.json()[0]
            # ── 2FA check ──
            totp_row = _get_user_totp_row(email)
            _2fa_enabled = totp_row and totp_row.get('totp_enabled')
            _2fa_remembered = False
            if _2fa_enabled:
                remember_tok = request.cookies.get('2fa_remember')
                if remember_tok and _verify_2fa_remember_token(remember_tok, email):
                    _2fa_remembered = True
            if _2fa_enabled and not _2fa_remembered:
                session['2fa_pending'] = True
                session['2fa_email'] = email
                session['2fa_is_admin'] = bool(_user_row.get('is_admin'))
                session['2fa_permissions'] = _user_row.get('permissions') or dict(_DEFAULT_PERMISSIONS)
                session['2fa_attempts'] = 0
                try:
                    requests.post(f"{SUPABASE_URL}/rest/v1/login_audit",
                                  json={'email': email, 'provider': 'google', 'result': '2fa_pending',
                                        'user_agent': request.headers.get('User-Agent', '')},
                                  headers={'apikey': SUPABASE_SERVICE_KEY,
                                           'Authorization': f'Bearer {SUPABASE_SERVICE_KEY}'},
                                  timeout=5)
                except Exception:
                    pass
                return _jsonify_auth({'ok': True, '2fa_required': True})
            # ── Normal login (no 2FA) ──
            session['authenticated'] = True
            session['email'] = email
            session['auth_method'] = 'google'
            session['is_admin'] = bool(_user_row.get('is_admin'))
            session['permissions'] = _user_row.get('permissions') or dict(_DEFAULT_PERMISSIONS)
            # Audit log (fire and forget)
            try:
                requests.post(f"{SUPABASE_URL}/rest/v1/login_audit",
                              json={'email': email, 'provider': 'google', 'result': 'allowed',
                                    'user_agent': request.headers.get('User-Agent', '')},
                              headers={'apikey': SUPABASE_SERVICE_KEY,
                                       'Authorization': f'Bearer {SUPABASE_SERVICE_KEY}'},
                              timeout=5)
            except Exception:
                pass
            return _jsonify_auth({'ok': True})
        # Not in allowed list — check for existing access request
        _ua = request.headers.get('User-Agent', '')
        try:
            _ar = requests.get(f"{SUPABASE_URL}/rest/v1/access_requests",
                               params={'email': f'eq.{email}', 'order': 'requested_at.desc', 'limit': '1',
                                       'select': 'id,status'},
                               headers={'apikey': SUPABASE_SERVICE_KEY,
                                        'Authorization': f'Bearer {SUPABASE_SERVICE_KEY}'},
                               timeout=10)
            _existing = _ar.json()[0] if _ar.ok and _ar.json() else None
        except Exception:
            _existing = None
        if _existing and _existing.get('status') == 'pending':
            _result = 'access_pending'
            _error = 'access_pending'
        else:
            # No existing request — show CAPTCHA before creating
            _result = 'access_captcha'
            _error = 'access_captcha'
        try:
            requests.post(f"{SUPABASE_URL}/rest/v1/login_audit",
                          json={'email': email, 'provider': 'google', 'result': _result,
                                'user_agent': _ua},
                          headers={'apikey': SUPABASE_SERVICE_KEY,
                                   'Authorization': f'Bearer {SUPABASE_SERVICE_KEY}'},
                          timeout=5)
        except Exception:
            pass
        # Store email temporarily so the request-access page knows who they are
        session['access_request_email'] = email
        return _jsonify_auth({'ok': False, 'error': _error})
    except Exception:
        return _jsonify_auth({'ok': False, 'error': 'db_error'})

@app.route('/logout')
def auth_logout():
    session.clear()
    return redirect(url_for('login_page'))

