try:
    from blueprints.gemini import gemini_bp
    app.register_blueprint(gemini_bp)
    import blueprints.gemini as _gemini_mod
    _gemini_mod._is_admin = _is_admin
    _gemini_mod._has_permission = _has_permission
    _gemini_mod._require_permission = _require_permission
    _gemini_mod.SUPABASE_URL = SUPABASE_URL
    _gemini_mod.SUPABASE_SERVICE_KEY = SUPABASE_SERVICE_KEY
    _gemini_mod._get_git_version = _get_git_version
except ImportError:
    pass  # blueprints/gemini.py not yet created


@app.route("/")
def index():
    # Redirect users who only have partner integrations (no PSPLA access)
    if not _is_admin():
        _perms = session.get('permissions') or _DEFAULT_PERMISSIONS
        _pspla_access = any(_perms.get(g) for g in ('searches', 'database', 'history', 'utilities'))
        if not _pspla_access:
            _has_shelly = _perms.get('shelly', False)
            _has_actuate = _perms.get('actuate', False)
            _has_cf = _perms.get('club_fitness', False)
            _has_gemini = _perms.get('gemini', False)
            # Find first available partner page
            _partner_pages = []
            if _has_actuate: _partner_pages.append('/actuate')
            if _has_shelly: _partner_pages.append('/shelly')
            if _has_cf: _partner_pages.append('/club-fitness')
            if _has_gemini: _partner_pages.append('/gemini')
            if _partner_pages:
                return redirect(_partner_pages[0])
    message = request.args.get("message", "")
    message_type = request.args.get("type", "success")

    companies = get_companies()

    total = len(companies)
    def is_licensed(c):
        v = c.get("pspla_licensed")
        return v is True or v == "true"

    def is_unlicensed(c):
        v = c.get("pspla_licensed")
        return v is False or v == "false"

    licensed = sum(1 for c in companies if is_licensed(c))
    expired = sum(1 for c in companies if is_unlicensed(c) and (c.get("pspla_license_status") or "").lower() == "expired")
    unlicensed = sum(1 for c in companies if is_unlicensed(c) and (c.get("pspla_license_status") or "").lower() != "expired")
    unknown = total - licensed - unlicensed - expired

    regions = sorted(set(c.get("region", "") for c in companies if c.get("region")))

    search_alive = _search_process_alive()
    search_paused = False
    if search_alive:
        from searcher import STATE_BACKEND
        if STATE_BACKEND == "supabase":
            try:
                from searcher import _read_search_state
                _ps = _read_search_state("paused")
                search_paused = bool(_ps.get("paused", False))
            except Exception:
                pass
        else:
            search_paused = os.path.exists(PAUSE_FLAG)

    git_version = _get_git_version()

    # Read live status for server-side progress bar pre-population
    init_status = {}
    if search_alive:
        from searcher import STATE_BACKEND as _sb
        if _sb == "supabase":
            try:
                from searcher import _read_search_state
                _ss = _read_search_state("status_json")
                sj = _ss.get("status_json")
                if sj and isinstance(sj, dict):
                    init_status = sj
            except Exception:
                pass
        elif os.path.exists(STATUS_FILE):
            try:
                with open(STATUS_FILE) as f:
                    init_status = json.load(f)
            except Exception:
                pass

    # Pre-load search terms for immediate render
    init_terms = _load_terms()

    # Pre-load last log lines for immediate render
    init_log_lines = []
    if search_alive and _sb == "supabase":
        try:
            _ll = _read_search_state("log_lines")
            lt = _ll.get("log_lines", "")
            if lt:
                init_log_lines = lt.split("\n")[-200:]
        except Exception:
            pass
    elif os.path.exists(LOG_FILE):
        try:
            with open(LOG_FILE, "r", encoding="utf-8", errors="replace") as f:
                raw = f.readlines()
            init_log_lines = [l.rstrip() for l in raw[-200:]]
        except Exception:
            pass

    return render_template_string(
        HTML_TEMPLATE,
        companies=companies,
        total=total,
        licensed=licensed,
        unlicensed=unlicensed,
        expired=expired,
        unknown=unknown,
        regions=regions,
        nz_regions=NZ_REGIONS,
        message=message,
        message_type=message_type,
        search_running=search_alive,
        search_paused=search_paused,
        schedule_enabled=_get_schedule_enabled(),
        init_status=init_status,
        init_terms=init_terms,
        init_log_lines=init_log_lines,
        git_version=git_version,
        github_repo=os.getenv("GITHUB_REPO", "wadeco2000/pspla-checker"),
        is_admin=_is_admin(),
        avatar_url=(_get_user_profile(session.get('email', '')) or {}).get('avatar_url', ''),
        user_perms=_user_perms_dict(),
        is_windows=os.name == "nt",
    )


