@app.route("/util/pspla-search", methods=["POST"])
def util_pspla_search():
    """Standalone PSPLA licence lookup — returns up to 10 raw results, no DB save."""
    from flask import jsonify
    name = request.json.get("name", "").strip()
    if not name:
        return jsonify({"error": "Name required"}), 400
    try:
        import requests as _req
        url = "https://forms.justice.govt.nz/forms/publicSolrProxy/solr/PSPLA/select"
        # Support % wildcard: convert to Solr * wildcard, otherwise wrap in quotes for phrase
        if "%" in name:
            q = f"name_txt:{name.replace('%','*')}"
        else:
            words = [w for w in name.split() if len(w) >= 2]
            q = " AND ".join(f"name_txt:{w}" for w in words) if words else f"name_txt:{name}"
        params = {
            "rows": "10", "fl": "*, score", "sort": "score desc",
            "json.nl": "map", "q": q,
            "fq": "jurisdictionCode_s:PSPLA AND permitHasBeenIssued_b:true",
            "wt": "json"
        }
        resp = _req.get(url, params=params,
                        headers={"User-Agent":"Mozilla/5.0","Referer":"https://forms.justice.govt.nz/search/PSPLA/"},
                        timeout=15)
        docs = resp.json().get("response", {}).get("docs", [])
        results = []
        for d in docs:
            def _val(f): v = d.get(f); return (v[0] if isinstance(v,list) else v) or ""
            results.append({
                "name":    _val("name_txt") or _val("caseTitle_s"),
                "status":  _val("permitStatus_s").capitalize(),
                "number":  _val("permitNumber_s"),
                "expiry":  _val("permitExpiry_dt")[:10] if _val("permitExpiry_dt") else "",
                "classes": _val("classOfLicence_s"),
                "address": _val("address_s"),
            })
        return jsonify({"results": results})
    except Exception as e:
        return jsonify({"error": _safe_error(e)}), 500


@app.route("/recheck-electrician", methods=["POST"])
def recheck_electrician_for_company():
    """Re-check MBIE Electrical Workers register — tries individual licence name then CO directors."""
    if not _is_admin():
        return _jsonify_auth({"ok": False, "error": "admin only"}), 403
    from flask import jsonify
    company_id   = request.json.get("id")
    name         = request.json.get("name", "").strip()       # individual_license name
    directors_str = request.json.get("directors", "").strip() # comma-separated CO directors
    names_to_try = []
    if name:
        names_to_try.append(name)
    for d in [x.strip() for x in directors_str.split(",") if x.strip()]:
        if d not in names_to_try:
            names_to_try.append(d)
    if not names_to_try:
        return jsonify({"error": "No names provided"}), 400
    _rl = _recheck_log_capture(); _rl.__enter__()
    snapshot = _fetch_company_snapshot(company_id)
    try:
        from searcher import check_electrician_licence
        result = {"found": False}
        for n in names_to_try:
            print(f"[EW] Checking electrician licence for: {n}")
            result = check_electrician_licence(n)
            if result.get("found"):
                print(f"[EW] Found: {result.get('ew_name')} | {result.get('ew_reg_number')} | Licensed: {result.get('ew_licensed')}")
                break
            else:
                print(f"[EW] No electrician licence found for {n}")
        headers = {"apikey": SUPABASE_KEY, "Authorization": f"Bearer {SUPABASE_KEY}",
                   "Content-Type": "application/json", "Prefer": "return=minimal"}
        requests.patch(
            f"{SUPABASE_URL}/rest/v1/Companies?id=eq.{company_id}",
            headers=headers,
            json={
                "ew_licensed":    result.get("ew_licensed"),
                "ew_name":        result.get("ew_name"),
                "ew_reg_number":  result.get("ew_reg_number"),
                "ew_city":        result.get("ew_city"),
                "ew_region":      result.get("ew_region"),
            },
        )
        from searcher import write_audit
        write_audit("updated", company_id, name,
                    changes=f"EW recheck: found={result.get('found')}, name={result.get('ew_name')}, reg={result.get('ew_reg_number')}",
                    triggered_by="manual (dashboard)",
                    snapshot_before=snapshot)
        return jsonify(result)
    except Exception as e:
        return jsonify({"error": _safe_error(e)}), 500
    finally:
        _rl.__exit__(None, None, None)


