@app.route("/api/actuate/flex-toggle", methods=["POST"])
def actuate_flex_toggle():
    """Toggle flex scheduling ON/OFF by linking/unlinking schedules."""
    if not ACTUATE_API_TOKEN:
        return jsonify({"ok": False, "error": "ACTUATE_API_TOKEN not configured."}), 500
    data = request.get_json(silent=True) or {}
    site_id = str(data.get("site_id", ""))
    fs_id = str(data.get("flex_schedule_id", ""))
    turn_on = data.get("turn_on", False)
    import re as _re_ft
    if not _re_ft.match(r"^[0-9]+$", site_id) or not _re_ft.match(r"^[0-9]+$", fs_id):
        return jsonify({"ok": False, "error": "Invalid IDs."}), 400
    try:
        import requests as _req
        _headers = {"Authorization": f"Token {ACTUATE_API_TOKEN}", "Content-Type": "application/json"}
        # Get all schedules for this site
        r = _req.get(f"{ACTUATE_BASE_URL}/api/schedule/",
            params={"customer__id": site_id}, headers=_headers, timeout=15)
        all_scheds = r.json().get("results", r.json()) if isinstance(r.json(), dict) else r.json()
        # Filter to enabled non-override schedules
        targets = [s for s in all_scheds if s.get("enabled") and not s.get("is_override")]
        if turn_on:
            targets = [s for s in targets if not s.get("flex_schedule")]
        else:
            targets = [s for s in targets if s.get("flex_schedule") == int(fs_id)]
        if not targets:
            return jsonify({"ok": True, "detail": "No schedules to update.", "updated": 0})
        updated = 0
        new_ids = []
        for s in targets:
            # GET full schedule, modify flex_schedule, PATCH
            rg = _req.get(f"{ACTUATE_BASE_URL}/api/schedule/{s['id']}/", headers=_headers, timeout=15)
            if not rg.ok:
                continue
            sched = rg.json()
            old_id = sched.pop("id", None)
            sched["flex_schedule"] = int(fs_id) if turn_on else None
            # Remove fields that cause issues
            for k in ["location_dusk_dawn", "override_start_date", "override_end_date"]:
                sched.pop(k, None)
            rp = _req.patch(f"{ACTUATE_BASE_URL}/api/schedule/{old_id}/", headers=_headers, json=sched, timeout=15)
            if rp.ok or rp.status_code == 201:
                body = rp.json()
                new_id = None
                if isinstance(body, list) and body:
                    new_id = body[0].get("id")
                elif isinstance(body, dict):
                    new_id = body.get("id")
                if new_id:
                    new_ids.append(new_id)
                # PATCH creates a new record — delete the old one if it still exists
                if new_id and new_id != old_id:
                    _req.delete(f"{ACTUATE_BASE_URL}/api/schedule/{old_id}/", headers=_headers, timeout=15)
                updated += 1
        # Clean up: delete phantom schedules (start_time=None)
        r2 = _req.get(f"{ACTUATE_BASE_URL}/api/schedule/",
            params={"customer__id": site_id}, headers=_headers, timeout=15)
        after_scheds = r2.json().get("results", r2.json()) if isinstance(r2.json(), dict) else r2.json()
        cleaned = 0
        for s in after_scheds:
            if s.get("enabled") and not s.get("is_override") and s.get("start_time") is None:
                _req.delete(f"{ACTUATE_BASE_URL}/api/schedule/{s['id']}/", headers=_headers, timeout=15)
                cleaned += 1
        action = "enabled" if turn_on else "disabled"
        return jsonify({"ok": True, "detail": f"Flex {action}. {updated} schedule(s) updated, {cleaned} phantom(s) cleaned.",
                        "updated": updated, "cleaned": cleaned})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 502


@app.route("/api/actuate/patriot-numbers", methods=["GET"])
def actuate_patriot_numbers():
    """Get patriot client numbers for all sites or a specific site."""
    if not ACTUATE_API_TOKEN:
        return jsonify({"ok": False, "error": "ACTUATE_API_TOKEN not configured."}), 500
    site_id = request.args.get("site_id", "")
    try:
        import requests as _req
        _headers = {"Authorization": f"Token {ACTUATE_API_TOKEN}"}
        # Get customers
        rc = _req.get(f"{ACTUATE_BASE_URL}/api/customer/", headers=_headers, timeout=15)
        customers = rc.json().get("results", rc.json()) if isinstance(rc.json(), dict) else rc.json()
        cust_map = {c["id"]: c.get("name", "?") for c in customers} if isinstance(customers, list) else {}
        # Get cameras
        cam_params = {"customer__id": site_id} if site_id else {}
        rcam = _req.get(f"{ACTUATE_BASE_URL}/api/camera/", params=cam_params, headers=_headers, timeout=15)
        cameras = rcam.json().get("results", rcam.json()) if isinstance(rcam.json(), dict) else rcam.json()
        # Group cameras by customer
        site_cameras = {}
        for c in cameras:
            cust = c.get("customer")
            cid = cust.get("id") if isinstance(cust, dict) else cust
            if cid not in site_cameras:
                site_cameras[cid] = []
            site_cameras[cid].append(c["id"])
        # For each site, get camera general_info for patriot + about for group
        results = []
        sites_to_check = [int(site_id)] if site_id else list(cust_map.keys())
        for sid in sites_to_check:
            cam_ids = site_cameras.get(sid, [])
            entry = {"site_id": sid, "site_name": cust_map.get(sid, "?"),
                     "patriot_client_no": None, "patriot_server": None, "group": None,
                     "active": None, "armed": None, "motion_pct": None,
                     "last_alert": None, "last_motion": None, "deployed_date": None,
                     "camera_count": len(site_cameras.get(sid, [])),
                     "cameras_active": 0, "cameras_inactive": 0}
            # Get group from about endpoint
            try:
                ra = _req.get(f"{ACTUATE_BASE_URL}/api/customer/{sid}/about/", headers=_headers, timeout=10)
                if ra.ok:
                    about = ra.json()
                    pg = about.get("parent_group")
                    if pg and isinstance(pg, dict):
                        entry["group"] = pg.get("name", "")
                    entry["active"] = about.get("active")
                    entry["armed"] = about.get("armed")
                    entry["last_alert"] = about.get("last_alert")
                    entry["last_motion"] = about.get("last_motion")
                    entry["deployed_date"] = about.get("deployed_date")
                    mp = about.get("motion_percentage")
                    entry["motion_pct"] = round(float(mp) * 100, 1) if mp is not None else None
            except Exception:
                pass
            # Get active/inactive camera counts
            try:
                _rc = _req.get(f"{ACTUATE_BASE_URL}/api/camera/site/",
                    params={"customer__id": str(sid), "page": "1"}, headers=_headers, timeout=10)
                if _rc.ok:
                    _rcj = _rc.json()
                    _site_cams = _rcj.get("results", _rcj) if isinstance(_rcj, dict) else _rcj
                    if isinstance(_site_cams, list):
                        entry["cameras_active"] = sum(1 for c in _site_cams if c.get("active"))
                        entry["cameras_inactive"] = sum(1 for c in _site_cams if not c.get("active"))
                        entry["camera_count"] = len(_site_cams)
            except Exception:
                pass
            # Get patriot from camera general_info
            if cam_ids:
                try:
                    rg = _req.get(f"{ACTUATE_BASE_URL}/api/camera/{cam_ids[0]}/general_info/", headers=_headers, timeout=10)
                    if rg.ok:
                        info = rg.json()
                        for stream in info.get("streams", []):
                            for pa in stream.get("patriot_alerts", []):
                                entry["patriot_client_no"] = pa.get("patriot_client_no")
                                entry["patriot_server"] = pa.get("patriot_server")
                                break
                            if entry["patriot_client_no"]:
                                break
                except Exception:
                    pass
            results.append(entry)
        # Sort by group then site name
        results.sort(key=lambda x: (x.get("group") or "zzz", x.get("site_name") or ""))
        return jsonify({"ok": True, "results": results})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 502


