# Allowed RPC methods (whitelist to prevent arbitrary command execution)
_SHELLY_ALLOWED_COMMANDS = {
    "Shelly.GetStatus", "Shelly.GetDeviceInfo", "Shelly.Reboot",
    "Switch.GetStatus", "Switch.Set",
    "Wifi.GetStatus", "Shelly.CheckForUpdate", "Shelly.Update",
}

@app.route("/api/shelly/command", methods=["POST"])
def shelly_command():
    _require_dashboard_auth()
    perm_block = _require_permission('shelly')
    if perm_block:
        return perm_block
    data = request.get_json(silent=True) or {}
    device_id = data.get("device_id", "").strip()
    method = data.get("method", "").strip()
    params = data.get("params", {})
    if not device_id:
        return jsonify({"ok": False, "error": "Missing device_id"}), 400
    if not method:
        return jsonify({"ok": False, "error": "Missing method"}), 400
    if method not in _SHELLY_ALLOWED_COMMANDS:
        return jsonify({"ok": False, "error": f"Method '{method}' not allowed"}), 403
    # Send the command
    success, detail = mqtt_send_command(device_id, method, params)
    # Log to command log
    try:
        user_email = session.get("email", "unknown")
        log_entry = {
            "device_id": device_id,
            "action": method,
            "triggered_by": user_email,
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "success": success,
        }
        log_headers = {"apikey": SUPABASE_SERVICE_KEY,
                       "Authorization": f"Bearer {SUPABASE_SERVICE_KEY}",
                       "Content-Type": "application/json",
                       "Prefer": "return=minimal"}
        requests.post(
            f"{SUPABASE_URL}/rest/v1/shelly_command_log",
            headers=log_headers, json=log_entry, timeout=10
        )
    except Exception as e:
        print(f"[shelly] Failed to log command: {e}")
    return jsonify({"ok": success, "detail": detail, "method": method})


# ╔═══════════════════════════════════════════════════════════════════════════╗
# ║  CLUB FITNESS — Challenge signups via Stripe payment links              ║
# ╚═══════════════════════════════════════════════════════════════════════════╝

import re as _re_mod

def _cf_value(cf_item):
    """Extract value from a Stripe custom field regardless of type (text/numeric/dropdown)."""
    if not cf_item:
        return ""
    for t in ("text", "numeric", "dropdown"):
        sub = cf_item.get(t)
        if sub and isinstance(sub, dict):
            return str(sub.get("value", ""))
    return ""

def _cf_label(cf_item):
    """Extract display label from a Stripe custom field."""
    if not cf_item:
        return ""
    lbl = cf_item.get("label", {})
    if isinstance(lbl, dict):
        return str(lbl.get("custom", "") or lbl.get("type", ""))
    return str(lbl)

def _stripe_sessions_to_rows(sessions_iter):
    """Convert Stripe checkout session iterator to list of dicts."""
    from datetime import datetime, timezone
    rows = []
    for s in sessions_iter:
        cf = s.get("custom_fields") or []
        rows.append({
            "stripe_session_id": s["id"],
            "created_at": datetime.fromtimestamp(s["created"], tz=timezone.utc).isoformat(),
            "card_name": (s.get("customer_details") or {}).get("name", "") or "",
            "customer_email": (s.get("customer_details") or {}).get("email", "") or "",
            "customer_phone": (s.get("customer_details") or {}).get("phone", "") or "",
            "custom_field_1": _cf_value(cf[0]) if len(cf) > 0 else "",
            "custom_field_2": _cf_value(cf[1]) if len(cf) > 1 else "",
            "custom_field_3": _cf_value(cf[2]) if len(cf) > 2 else "",
            "custom_field_1_label": _cf_label(cf[0]) if len(cf) > 0 else "",
            "custom_field_2_label": _cf_label(cf[1]) if len(cf) > 1 else "",
            "custom_field_3_label": _cf_label(cf[2]) if len(cf) > 2 else "",
        })
    return rows

_PLINK_RE = _re_mod.compile(r'^plink_[a-zA-Z0-9_]+$')

def _validate_payment_link(pl):
    """Validate and return payment link ID, or None."""
    if pl and _PLINK_RE.match(pl):
        return pl
    return None


@app.route("/api/club-fitness/send-booking-email", methods=["POST"])
@app.route("/api/club-fitness/email-template", methods=["GET", "POST"])
def club_fitness_email_template():
    """GET: fetch email template. POST: update it."""
    if request.method == "GET":
        name = request.args.get("name", "booking_reminder")
        try:
            r = requests.get(f"{SUPABASE_URL}/rest/v1/challenge_email_templates",
                params={"select": "*", "name": f"eq.{name}"},
                headers={"apikey": SUPABASE_SERVICE_KEY, "Authorization": f"Bearer {SUPABASE_SERVICE_KEY}"},
                timeout=10)
            if r.ok and r.json():
                return jsonify({"ok": True, "template": r.json()[0]})
            return jsonify({"ok": True, "template": None})
        except Exception as e:
            return jsonify({"ok": False, "error": str(e)}), 502
    # POST — update
    data = request.json or {}
    name = data.get("name", "booking_reminder")
    subject = data.get("subject", "").strip()
    body = data.get("body", "").strip()
    if not subject or not body:
        return jsonify({"ok": False, "error": "Subject and body required"}), 400
    try:
        r = requests.post(f"{SUPABASE_URL}/rest/v1/challenge_email_templates",
            json={"name": name, "subject": subject, "body": body, "updated_at": "now()"},
            headers={"apikey": SUPABASE_SERVICE_KEY, "Authorization": f"Bearer {SUPABASE_SERVICE_KEY}",
                     "Content-Type": "application/json", "Prefer": "resolution=merge-duplicates,return=representation"},
            timeout=10)
        return jsonify({"ok": True, "template": r.json()[0] if r.ok and r.json() else None})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 502


@app.route("/api/club-fitness/send-booking-email", methods=["POST"])
def club_fitness_send_booking_email():
    """Send a booking reminder email to a challenge signup."""
    data = request.json or {}
    to_email = data.get("email", "").strip()
    subject = data.get("subject", "").strip()
    body = data.get("body", "").strip()
    if not to_email or not subject or not body:
        return jsonify({"ok": False, "error": "Email, subject, and body required"}), 400
    if not CF_SMTP_USER or not CF_SMTP_PASS:
        return jsonify({"ok": False, "error": "CF_SMTP not configured"}), 500
    try:
        import smtplib
        from email.mime.multipart import MIMEMultipart
        from email.mime.text import MIMEText
        msg = MIMEMultipart("alternative")
        msg["Subject"] = subject
        msg["From"] = f"{CF_SMTP_FROM_NAME} <{CF_SMTP_USER}>"
        msg["To"] = to_email
        msg.attach(MIMEText(body, "plain"))
        html_body = body.replace("\n", "<br>")
        msg.attach(MIMEText(f"<html><body style='font-family:Arial,sans-serif;font-size:14px;color:#333;'>{html_body}</body></html>", "html"))
        with smtplib.SMTP("smtp.gmail.com", 587) as server:
            server.ehlo()
            server.starttls()
            server.login(CF_SMTP_USER, CF_SMTP_PASS)
            server.sendmail(CF_SMTP_USER, to_email, msg.as_string())
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 502


@app.route("/api/club-fitness/signups")
def club_fitness_signups():
    """Fetch signups from Stripe, auto-sync to Supabase, return merged data with custom columns preserved."""
    if not STRIPE_SECRET_KEY:
        return jsonify({"ok": False, "error": "STRIPE_SECRET_KEY not configured."}), 500
    pl = _validate_payment_link(request.args.get("payment_link", "").strip())
    if not pl:
        pl = _validate_payment_link(STRIPE_DEFAULT_PAYMENT_LINK)
    if not pl:
        return jsonify({"ok": False, "error": "No valid payment_link provided."}), 400
    try:
        import stripe
        stripe.api_key = STRIPE_SECRET_KEY
        it = stripe.checkout.Session.list(payment_link=pl, status="complete", limit=100).auto_paging_iter()
        stripe_rows = _stripe_sessions_to_rows(it)
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 502
    # Auto-sync: upsert new entries to Supabase (does NOT overwrite gym_scales_weight / final_weight)
    from datetime import datetime, timezone
    now_iso = datetime.now(timezone.utc).isoformat()
    _upsert_fields = ["stripe_session_id", "payment_link", "created_at", "card_name",
                       "customer_email", "customer_phone", "custom_field_1", "custom_field_2",
                       "custom_field_3", "custom_field_1_label", "custom_field_2_label",
                       "custom_field_3_label", "synced_at"]
    for row in stripe_rows:
        upsert = {k: row.get(k, "") for k in _upsert_fields if k != "payment_link" and k != "synced_at"}
        upsert["payment_link"] = pl
        upsert["synced_at"] = now_iso
        try:
            requests.post(
                f"{SUPABASE_URL}/rest/v1/challenge_signups",
                headers={
                    "apikey": SUPABASE_SERVICE_KEY,
                    "Authorization": f"Bearer {SUPABASE_SERVICE_KEY}",
                    "Content-Type": "application/json",
                    "Prefer": "resolution=merge-duplicates,return=minimal"
                },
                json=upsert, timeout=15
            )
        except Exception:
            pass
    # Update last_sync_at on the challenge_links row
    try:
        requests.patch(
            f"{SUPABASE_URL}/rest/v1/challenge_links",
            params={"payment_link_id": f"eq.{pl}"},
            json={"last_sync_at": now_iso},
            headers={"apikey": SUPABASE_SERVICE_KEY, "Authorization": f"Bearer {SUPABASE_SERVICE_KEY}",
                     "Content-Type": "application/json", "Prefer": "return=minimal"},
            timeout=10
        )
    except Exception:
        pass
    # Return stored data (includes custom columns like gym_scales_weight, final_weight)
    try:
        sr = requests.get(
            f"{SUPABASE_URL}/rest/v1/challenge_signups",
            params={"payment_link": f"eq.{pl}", "select": "*", "order": "created_at.desc"},
            headers={"apikey": SUPABASE_SERVICE_KEY, "Authorization": f"Bearer {SUPABASE_SERVICE_KEY}"},
            timeout=30
        )
        if sr.ok:
            stored = sr.json()
            return jsonify({"ok": True, "signups": stored, "count": len(stored), "payment_link": pl})
    except Exception:
        pass
    # Fallback: return Stripe data without custom columns
    return jsonify({"ok": True, "signups": stripe_rows, "count": len(stripe_rows), "payment_link": pl})


