    template = (data.get("template") or "").strip()
    ai_instructions = (data.get("ai_instructions") or "").strip()
    if not template:
        return jsonify({"ok": False, "error": "Template is required."}), 400
    api_key = os.getenv("ANTHROPIC_API_KEY", "")
